mapper.update:
UPDATE agent_install_tokens
SET used_at = #{now}
WHERE user_id = #{userId}
  AND used_at IS NULL
  AND expires_at > #{now}

mapper.select:
SELECT id, user_id, token_hash, expires_at, used_at, used_by_agent_id, extension_count, created_at
FROM agent_install_tokens
WHERE token_hash = #{tokenHash}
  AND used_at IS NULL
  AND expires_at > #{now}

mapper.update:
UPDATE agent_install_tokens
SET expires_at = #{expiresAt},
    extension_count = extension_count + 1
WHERE id = #{id}
  AND used_at IS NULL
  AND expires_at > #{now}
  AND extension_count < #{maxExtensions}

UPDATE agent_install_tokens
SET used_at = #{now},
    used_by_agent_id = #{agentId}
WHERE id = #{id}
  AND used_at IS NULL
  AND expires_at > #{now}

mapper.delete:
DELETE FROM agent_install_tokens
WHERE expires_at < #{cutoff}
   OR used_at < #{cutoff}
